-- ===== 1. 임플란트 (45개) =====
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
('implant', '임플란트', 'Dental Implant', '임플란트', '상실된 치아를 대체하는 인공치아 시술', '치아가 빠진 자리의 턱뼈에 티타늄 나사(픽스쳐)를 심고, 그 위에 인공 치아(크라운)를 연결하는 시술입니다. 자연치아와 가장 유사한 기능과 심미성을 제공하며, 주변 치아를 손상시키지 않는 장점이 있습니다. 강남치과의원에서는 구강외과 전문의가 3D CT 기반 정밀 진단 후 디지털 가이드를 이용하여 안전하게 시술합니다.', 'implant', '픽스쳐,어버트먼트,크라운,골유착,뼈이식', 1, 1),
('fixture', '픽스쳐', 'Fixture', '임플란트', '턱뼈에 심는 티타늄 나사', '임플란트의 뿌리 역할을 하는 티타늄 합금 나사입니다. 턱뼈에 식립되어 2~4개월간 뼈와 결합(골유착)된 후, 그 위에 보철물을 연결합니다. 티타늄은 생체친화성이 뛰어나 인체 거부반응이 거의 없습니다.', 'implant', '임플란트,골유착,티타늄,식립', 2, 0),
('abutment', '어버트먼트', 'Abutment', '임플란트', '픽스쳐와 크라운을 연결하는 중간 부품', '임플란트 픽스쳐(나사) 위에 올라가는 연결 기둥입니다. 픽스쳐와 크라운(인공치아) 사이를 단단히 연결하며, 잇몸 위로 올라오는 부분이므로 잇몸 형태를 자연스럽게 만드는 역할도 합니다.', 'implant', '픽스쳐,크라운,임플란트', 3, 0),
('osseointegration', '골유착', 'Osseointegration', '임플란트', '임플란트와 턱뼈가 단단히 결합하는 과정', '임플란트 픽스쳐를 턱뼈에 식립한 후, 2~4개월에 걸쳐 뼈세포가 티타늄 표면에 자라 붙어 단단히 결합하는 과정입니다. 골유착이 완성되어야 씹는 힘을 견딜 수 있으며, 임플란트 성공의 핵심 과정입니다.', 'implant', '픽스쳐,임플란트,치조골', 3, 0),
('bone-graft', '뼈이식', 'Bone Graft', '임플란트', '부족한 턱뼈를 보충하는 수술', '임플란트를 심기에 턱뼈가 부족할 때, 뼈 이식재를 넣어 뼈의 양과 질을 보충하는 수술입니다. 자가골, 동종골, 이종골, 합성골 등 다양한 이식재가 사용되며, 4~6개월 후 새로운 뼈로 대체됩니다.', 'bone-graft', '임플란트,치조골,GBR,차폐막', 2, 1),
('sinus-lift', '상악동 거상술', 'Sinus Lift', '임플란트', '윗턱 어금니 부위 뼈를 보충하는 수술', '윗턱 어금니 부위에는 상악동(부비강)이 있어 뼈가 얇은 경우가 많습니다. 상악동 점막을 위로 들어올리고 그 아래에 뼈 이식재를 채워 임플란트 식립 공간을 확보하는 수술입니다.', 'sinus-lift', '임플란트,뼈이식,상악동,윗턱', 3, 1),
('gbr', 'GBR', 'Guided Bone Regeneration', '임플란트', '차폐막을 이용한 뼈 재생 유도술', '뼈가 부족한 부위에 차폐막(멤브레인)을 씌워 뼈 이식재가 안정적으로 자리잡도록 돕는 기술입니다. 차폐막이 연조직의 침투를 막고 뼈세포만 자라도록 유도하여 새로운 뼈가 형성됩니다.', 'bone-graft', '뼈이식,차폐막,임플란트', 3, 0),
('membrane', '차폐막', 'Membrane', '임플란트', '뼈이식 시 사용하는 보호막', '뼈이식 수술 시 이식재 위에 덮는 얇은 막입니다. 잇몸 조직이 뼈 이식재 안으로 자라 들어오는 것을 차단하고, 뼈세포가 안정적으로 재생되도록 보호합니다. 흡수성과 비흡수성이 있습니다.', 'bone-graft', 'GBR,뼈이식', 3, 0),
('immediate-implant', '즉시 임플란트', 'Immediate Implant', '임플란트', '발치 당일 임플란트를 식립하는 방법', '치아를 뽑은 직후 같은 자리에 바로 임플란트를 심는 시술입니다. 치조골이 충분하고 염증이 없는 경우에 가능하며, 전체 치료 기간을 단축할 수 있습니다.', 'implant', '임플란트,발치,치조골', 3, 0),
('implant-overdenture', '임플란트 오버덴처', 'Implant Overdenture', '임플란트', '임플란트로 고정하는 틀니', '2~4개의 임플란트를 턱뼈에 심고, 그 위에 틀니를 고정하는 방식입니다. 일반 틀니보다 훨씬 안정적이며, 씹는 힘이 좋고 빠지지 않습니다. 완전 무치악 환자에게 효과적입니다.', 'implant', '임플란트,틀니,무치악', 2, 0),
('titanium', '티타늄', 'Titanium', '임플란트', '임플란트 픽스쳐의 주요 소재', '임플란트 나사에 사용되는 금속으로, 생체친화성이 매우 뛰어나 인체 거부반응이 거의 없습니다. 가벼우면서도 강도가 높아 치과뿐 아니라 정형외과, 항공우주 분야에서도 사용됩니다.', 'implant', '픽스쳐,임플란트,골유착', 2, 0),
('digital-guide', '디지털 가이드', 'Digital Surgical Guide', '임플란트', '3D 설계 기반 임플란트 식립 가이드', '3D CT와 디지털 구강 스캔 데이터를 기반으로 컴퓨터로 설계한 맞춤형 수술 보조 장치입니다. 임플란트를 계획된 정확한 위치, 각도, 깊이에 식립할 수 있도록 안내하여 수술 정확도와 안전성을 높입니다.', 'implant', '임플란트,3D CT,디지털', 2, 0),
('healing-abutment', '힐링 어버트먼트', 'Healing Abutment', '임플란트', '잇몸 형태를 잡아주는 임시 기둥', '임플란트 식립 후 잇몸이 자연스러운 모양으로 치유되도록 돕는 임시 연결 기둥입니다. 골유착 기간 동안 잇몸 위에 노출되어 있으며, 최종 보철 장착 전에 제거됩니다.', 'implant', '어버트먼트,임플란트,잇몸', 3, 0),
('periimplantitis', '임플란트 주위염', 'Peri-implantitis', '임플란트', '임플란트 주변 잇몸과 뼈에 생기는 염증', '임플란트 주위 잇몸과 뼈에 세균 감염으로 발생하는 염증성 질환입니다. 방치하면 임플란트를 지지하는 뼈가 녹아 임플란트가 흔들리거나 빠질 수 있습니다. 정기적인 관리와 검진으로 예방이 중요합니다.', 'implant', '임플란트,잇몸,치주염', 2, 0),
('alveolar-bone', '치조골', 'Alveolar Bone', '임플란트', '치아를 감싸고 지지하는 턱뼈', '치아 뿌리를 둘러싸고 있는 턱뼈 부분입니다. 치아가 빠지면 자극이 없어져 자연적으로 흡수(녹음)되며, 이를 치조골 흡수라 합니다. 임플란트는 이 치조골에 식립됩니다.', 'implant', '뼈이식,임플란트,발치', 2, 0),
('neo-implant', '네오 임플란트', 'Neo Implant', '임플란트', '국산 프리미엄 임플란트 시스템', '대한민국 기술로 개발된 프리미엄 임플란트 시스템입니다. SLA 표면처리 기술로 골유착이 빠르고, 다양한 직경과 길이의 픽스쳐를 제공하여 환자 상황에 맞는 최적의 선택이 가능합니다.', 'implant', '임플란트,픽스쳐,골유착', 2, 0),

-- ===== 2. 교정 (30개) =====
('orthodontics', '치아교정', 'Orthodontics', '교정', '치아 배열과 교합을 바로잡는 치료', '삐뚤어진 치아나 부정교합을 바로잡는 치료입니다. 금속 교정, 세라믹 교정, 투명 교정(인비절라인) 등 다양한 방법이 있으며, 심미성과 구강 기능을 동시에 개선합니다.', 'invisalign', '인비절라인,브라켓,부정교합', 1, 1),
('invisalign', '인비절라인', 'Invisalign', '교정', '세계 1위 투명교정 시스템', '얇고 투명한 플라스틱 장치(얼라이너)를 착용하여 치아를 이동시키는 교정 방법입니다. 눈에 잘 띄지 않고, 탈착이 가능하여 식사와 양치가 자유롭습니다. iTero 스캐너로 3D 시뮬레이션 후 맞춤 제작됩니다.', 'invisalign', '얼라이너,투명교정,클린체크', 1, 1),
('aligner', '얼라이너', 'Aligner', '교정', '투명교정에 사용하는 투명 장치', '환자의 치아 형태에 맞춰 제작된 투명한 플라스틱 교정 장치입니다. 1~2주마다 새 얼라이너로 교체하며, 각 단계별로 조금씩 치아를 이동시킵니다. 하루 20~22시간 착용을 권장합니다.', 'invisalign', '인비절라인,투명교정', 1, 0),
('bracket', '브라켓', 'Bracket', '교정', '치아에 부착하는 교정 장치', '교정 치료 시 각 치아 표면에 접착하는 작은 장치입니다. 와이어를 고정하여 치아에 힘을 전달하며, 금속, 세라믹, 레진 등 다양한 소재가 있습니다.', 'invisalign', '와이어,교정,밴드', 1, 0),
('malocclusion', '부정교합', 'Malocclusion', '교정', '윗니와 아랫니가 제대로 맞물리지 않는 상태', '위아래 치아가 정상적으로 맞물리지 않는 상태를 말합니다. 1급(치아 배열 문제), 2급(윗턱 돌출), 3급(아랫턱 돌출) 등으로 분류됩니다. 저작 기능과 심미성에 영향을 미칩니다.', 'invisalign', '교정,과개교합,개방교합', 2, 0),
('overbite', '과개교합', 'Deep Bite / Overbite', '교정', '윗니가 아랫니를 과도하게 덮는 상태', '정상적으로 윗니가 아랫니를 2~3mm 덮지만, 과개교합은 이보다 훨씬 깊게 덮는 상태입니다. 아랫니가 윗턱 잇몸을 물기도 합니다. 턱관절 장애의 원인이 될 수 있습니다.', 'invisalign', '부정교합,교정', 2, 0),
('openbite', '개방교합', 'Open Bite', '교정', '윗니와 아랫니가 맞닿지 않는 상태', '위아래 앞니가 서로 맞닿지 않아 벌어진 상태입니다. 음식물을 앞니로 끊어 먹기 어렵고, 발음에도 영향을 줄 수 있습니다. 습관(혀 내밀기, 손가락 빨기)이 원인인 경우가 많습니다.', 'invisalign', '부정교합,교정', 2, 0),
('retainer', '유지장치', 'Retainer', '교정', '교정 후 치아 위치를 유지하는 장치', '교정 치료 완료 후 치아가 원래 위치로 돌아가는 것(재발)을 방지하기 위해 착용하는 장치입니다. 고정식(치아 안쪽에 접착)과 가철식(탈착 가능) 두 종류가 있습니다.', 'invisalign', '교정,얼라이너', 1, 0),
('clincheck', '클린체크', 'ClinCheck', '교정', '인비절라인 3D 치료 시뮬레이션', '인비절라인 교정 전 컴퓨터로 치아 이동 과정을 3D로 미리 보여주는 시뮬레이션 프로그램입니다. 환자가 치료 전에 예상 결과를 확인할 수 있어 만족도가 높습니다.', 'invisalign', '인비절라인,디지털', 2, 0),
('itero', 'iTero 스캐너', 'iTero Scanner', '교정', '인비절라인용 디지털 구강 스캐너', '인비절라인 교정을 위해 구강 내부를 3D로 스캔하는 디지털 장비입니다. 기존 본뜨기(인상채득) 없이 정밀한 디지털 데이터를 얻을 수 있어 환자 불편감이 없습니다.', 'invisalign', '인비절라인,디지털,클린체크', 2, 0),
('crowding', '총생', 'Crowding', '교정', '치아가 겹쳐서 자라난 상태', '턱뼈의 공간에 비해 치아가 크거나 많아서 치아들이 겹치거나 비틀어진 상태입니다. 양치가 어려워 충치와 치주질환의 위험이 높아집니다.', 'invisalign', '부정교합,교정', 1, 0),
('spacing', '치간 이개', 'Spacing', '교정', '치아 사이에 공간이 벌어진 상태', '치아 사이에 비정상적으로 넓은 간격이 있는 상태입니다. 선천적 원인, 치아 크기 불균형, 혀 내밀기 습관 등이 원인입니다. 교정 또는 라미네이트로 치료 가능합니다.', 'invisalign', '교정,라미네이트,부정교합', 1, 0),
('crossbite', '반대교합', 'Crossbite', '교정', '위아래 치아의 교합이 반대로 물리는 상태', '정상적으로 윗니가 아랫니 바깥에 위치해야 하지만, 반대로 아랫니가 윗니 바깥에 위치하는 상태입니다. 부분적 또는 전체적으로 발생할 수 있으며, 조기 치료가 권장됩니다.', 'invisalign', '부정교합,교정', 2, 0),
('tmj', '턱관절 장애', 'TMJ Disorder', '교정', '턱관절의 통증이나 기능 이상', '턱관절(측두하악관절)에 통증, 소리, 개구 제한 등이 나타나는 질환입니다. 이갈이, 이 악물기, 부정교합, 스트레스 등이 원인이며, 교합 조정이나 스플린트 치료가 필요할 수 있습니다.', NULL, '교정,부정교합,스플린트', 2, 0),

-- ===== 3. 보철/심미 (40개) =====
('crown', '크라운', 'Crown', '보철', '치아 전체를 감싸는 보철물', '손상된 치아 전체를 덮어 씌우는 모자 형태의 보철물입니다. 충치가 심하거나, 신경치료 후, 깨진 치아 등에 사용합니다. 올세라믹, 지르코니아, PFM 등 다양한 소재가 있습니다.', 'crown', '올세라믹,지르코니아,CEREC', 1, 1),
('cerec', 'CEREC', 'CEREC (Chairside Economical Restoration of Esthetic Ceramics)', '보철', 'CAD/CAM 기반 당일 보철 제작 시스템', '디지털 스캔 → 컴퓨터 설계 → 밀링 → 소성까지 1~2시간 만에 세라믹 보철물을 제작하는 첨단 시스템입니다. 본뜨기 없이 당일 치료 완료가 가능하며, 0.01mm 정밀도로 제작됩니다.', 'cerec', 'CAD/CAM,밀링,PrimeScan', 1, 1),
('inlay', '인레이', 'Inlay', '보철', '치아 안쪽을 채우는 맞춤형 보철물', '충치를 제거한 후 빈 공간을 정확하게 맞춤 제작한 보철물로 채우는 치료입니다. 레진 충전보다 정밀하고 내구성이 우수합니다. CEREC으로 당일 세라믹 인레이 제작이 가능합니다.', 'cerec', '온레이,충치,CEREC', 1, 0),
('onlay', '온레이', 'Onlay', '보철', '치아 교두까지 덮는 큰 인레이', '인레이보다 손상 범위가 클 때, 치아의 교두(뾰족한 부분)까지 덮어 보호하는 보철물입니다. 크라운보다 치아 삭제량이 적어 건강한 치아 구조를 더 많이 보존할 수 있습니다.', 'cerec', '인레이,크라운,CEREC', 2, 0),
('laminate', '라미네이트', 'Laminate Veneer', '보철', '치아 앞면에 부착하는 얇은 세라믹', '치아 앞면을 0.3~0.5mm만 삭제하고, 얇은 세라믹 판을 접착하는 심미 보철 방법입니다. 치아 색상, 형태, 크기를 개선하며, 치아 삭제량이 적어 보존적입니다.', 'cosmetic', '심미보철,세라믹,올세라믹', 1, 1),
('zirconia', '지르코니아', 'Zirconia', '보철', '고강도 세라믹 보철 소재', '인공 다이아몬드라 불리는 고강도 세라믹 소재입니다. 어금니 크라운에 특히 적합하며, 금속 없이 자연치아에 가까운 색감을 재현합니다. 생체친화성이 뛰어나 잇몸 변색이 없습니다.', 'crown', '크라운,보철,세라믹', 1, 0),
('all-ceramic', '올세라믹', 'All-Ceramic', '보철', '금속 없이 세라믹만으로 만든 보철', '금속 프레임 없이 순수 세라믹으로만 제작한 보철물입니다. 빛 투과성이 좋아 자연치아와 거의 구분이 되지 않으며, 앞니 보철에 가장 적합합니다. e.max 리튬디실리케이트가 대표적입니다.', 'crown', '크라운,라미네이트,e.max', 1, 0),
('emax', 'e.max', 'IPS e.max', '보철', '리튬디실리케이트 세라믹 소재', '올세라믹 보철의 대표적 소재로, 높은 강도와 뛰어난 심미성을 겸비합니다. 자연치아와 유사한 투명도를 가지며, CEREC 시스템으로 당일 제작이 가능합니다.', 'cerec', '올세라믹,크라운,CEREC', 2, 0),
('pfm', 'PFM 크라운', 'Porcelain-Fused-to-Metal', '보철', '금속 위에 도자기를 입힌 크라운', '금속 프레임 위에 도자기(포세린)를 구워 입힌 크라운입니다. 과거에 가장 널리 사용되었으나, 잇몸 변색과 금속 알레르기 가능성이 있어 현재는 올세라믹이나 지르코니아가 선호됩니다.', 'crown', '크라운,금속,올세라믹', 2, 0),
('bridge', '브릿지', 'Bridge', '보철', '빠진 치아 양쪽을 이용한 고정식 보철', '빠진 치아 양옆의 건강한 치아를 깎아 기둥(지대치)으로 삼고, 3개 이상의 크라운을 연결하여 빈 자리를 채우는 보철입니다. 임플란트의 대안이지만, 건강한 치아를 삭제해야 하는 단점이 있습니다.', 'crown', '크라운,임플란트,지대치', 2, 0),
('denture', '틀니', 'Denture', '보철', '분리 가능한 의치', '여러 개 또는 전체 치아가 없을 때 사용하는 탈착식 보철물입니다. 부분틀니(일부 치아 상실)와 완전틀니(전체 치아 상실)가 있으며, 임플란트와 결합하여 안정성을 높일 수 있습니다.', NULL, '부분틀니,완전틀니,임플란트 오버덴처', 1, 0),
('cad-cam', 'CAD/CAM', 'Computer-Aided Design/Manufacturing', '보철', '컴퓨터로 설계하고 기계로 제작하는 기술', '컴퓨터 지원 설계(CAD)와 컴퓨터 지원 제조(CAM)를 결합한 디지털 보철 제작 기술입니다. CEREC 시스템이 대표적이며, 정밀한 보철물을 빠르게 제작할 수 있습니다.', 'cerec', 'CEREC,밀링,디지털', 2, 0),
('milling', '밀링', 'Milling', '보철', '세라믹 블록을 깎아 보철물을 만드는 과정', 'CAD 소프트웨어로 설계된 보철물을 세라믹 블록에서 정밀하게 깎아내는 공정입니다. CEREC MC X 같은 밀링 머신이 사용되며, 15분 내에 보철물 형태가 완성됩니다.', 'cerec', 'CEREC,CAD/CAM,세라믹', 2, 0),
('sintering', '소성', 'Sintering', '보철', '세라믹 보철물을 고온에서 굽는 과정', '밀링으로 깎아낸 세라믹 보철물을 1600℃ 고온에서 소성(구움)하여 최종 강도와 색감을 완성하는 과정입니다. SpeedFire 소성로를 사용하면 15분 내에 완료됩니다.', 'cerec', 'CEREC,밀링,SpeedFire', 3, 0),
('primescan', 'PrimeScan', 'PrimeScan', '보철', '프리미엄 디지털 구강 스캐너', 'Dentsply Sirona의 최신 구강 스캐너로, 기존 본뜨기를 대체합니다. 초당 100만개 이상의 3D 포인트를 측정하여 매우 정밀한 디지털 인상을 채득합니다.', 'cerec', 'CEREC,디지털,구강스캔', 2, 0),
('speedfire', 'SpeedFire', 'SpeedFire', '보철', '초고속 세라믹 소성로', 'CEREC 시스템의 소성 장비로, 1600℃까지 급속 가열하여 지르코니아 보철물을 15분 만에 소성 완료합니다. 기존 8시간 이상 걸리던 소성 시간을 획기적으로 단축합니다.', 'cerec', 'CEREC,소성,지르코니아', 3, 0),
('smile-line', '스마일 라인', 'Smile Line', '보철', '미소 지을 때 보이는 치아의 곡선', '미소 시 윗입술 아래로 보이는 치아의 곡선입니다. 심미 보철에서는 이 스마일 라인을 아랫입술의 곡선과 조화롭게 설계하여 자연스럽고 매력적인 미소를 만듭니다.', 'cosmetic', '심미보철,라미네이트', 1, 0),
('shade-matching', '색조 선택', 'Shade Matching', '보철', '보철물의 색을 자연치아에 맞추는 과정', '보철물 제작 시 주변 자연치아와 가장 잘 어울리는 색상을 선택하는 과정입니다. 비타(VITA) 쉐이드 가이드를 사용하거나 디지털 비색계로 정확하게 측정합니다.', 'cerec', '보철,올세라믹,심미', 2, 0),
('temporary-crown', '임시 크라운', 'Temporary Crown', '보철', '최종 보철 전 임시로 씌우는 크라운', '최종 보철물이 완성되기 전까지 치아를 보호하고 심미성을 유지하기 위해 착용하는 임시 보철물입니다. CEREC 당일 보철의 경우 임시 크라운이 필요 없습니다.', 'crown', '크라운,보철,CEREC', 1, 0),
('whitening', '치아 미백', 'Tooth Whitening', '보철', '치아 색상을 밝게 하는 시술', '과산화수소 또는 카바마이드 퍼옥사이드 성분을 사용하여 치아 내부의 착색 물질을 분해, 치아를 밝게 만드는 시술입니다. 오피스 미백(병원)과 홈 미백(자가) 방법이 있습니다.', 'whitening', '오피스 미백,홈 미백,착색', 1, 1),

-- ===== 4. 일반/보존 (35개) =====
('cavity', '충치', 'Dental Caries / Cavity', '일반', '세균에 의해 치아가 썩는 질환', '구강 내 세균이 음식물의 당분을 분해하면서 산을 생성하고, 이 산이 치아의 법랑질과 상아질을 녹여 구멍을 만드는 질환입니다. 초기에는 증상이 없지만 진행되면 통증이 생깁니다.', 'cavity', '법랑질,상아질,레진,충전', 1, 1),
('resin', '레진', 'Composite Resin', '일반', '치아색 충전 재료', '충치를 제거한 후 빈 공간을 메우는 치아색 플라스틱 복합 재료입니다. 색상이 자연치아와 유사하여 심미적이며, 소량의 충치 치료에 주로 사용됩니다. 12세 이하 어린이는 보험 적용됩니다.', 'resin', '충치,충전,인레이', 1, 0),
('root-canal', '신경치료', 'Root Canal Treatment', '일반', '감염된 치아 신경을 제거하는 치료', '충치가 치아 내부의 신경(치수)까지 진행되었을 때, 감염된 신경 조직을 제거하고 소독한 후 충전재로 밀봉하는 치료입니다. 치아를 보존하는 마지막 단계의 치료입니다.', 'root-canal', '치수,근관,충치,크라운', 1, 1),
('enamel', '법랑질', 'Enamel', '일반', '치아의 가장 바깥 층', '치아 표면을 덮고 있는 인체에서 가장 단단한 조직입니다. 96%가 무기질로 구성되어 있으며, 씹는 힘과 온도 변화로부터 치아 내부를 보호합니다. 한번 손상되면 재생되지 않습니다.', 'cavity', '상아질,치수,충치', 2, 0),
('dentin', '상아질', 'Dentin', '일반', '법랑질 안쪽의 치아 층', '법랑질 아래에 있는 치아의 주요 구조물입니다. 법랑질보다 부드럽고, 미세한 관(상아세관)이 있어 외부 자극이 신경으로 전달됩니다. 충치가 상아질에 도달하면 시린 증상이 나타납니다.', 'cavity', '법랑질,치수,시린이', 2, 0),
('pulp', '치수', 'Dental Pulp', '일반', '치아 내부의 신경과 혈관 조직', '치아 중심부에 위치한 부드러운 조직으로, 신경, 혈관, 결합조직으로 구성됩니다. 치아에 영양을 공급하고 감각을 전달합니다. 충치가 치수까지 진행되면 극심한 통증이 생깁니다.', 'root-canal', '신경치료,법랑질,상아질', 2, 0),
('root-canal-filling', '근관 충전', 'Root Canal Filling', '일반', '신경치료 후 빈 공간을 메우는 과정', '신경치료로 감염된 신경을 제거한 후, 깨끗이 소독된 근관(신경이 있던 관)을 거타퍼쳐와 실러로 빈틈없이 밀봉하는 과정입니다.', 'root-canal', '신경치료,거타퍼쳐,근관', 3, 0),
('gutta-percha', '거타퍼쳐', 'Gutta-Percha', '일반', '근관 충전에 사용하는 고무 재료', '신경치료 후 빈 근관을 밀봉하는 데 사용하는 천연 고무 유래 재료입니다. 생체친화성이 좋고, 근관 내에서 안정적으로 유지되어 세균 재감염을 방지합니다.', 'root-canal', '신경치료,근관 충전', 3, 0),
('dental-caries', '치아우식증', 'Dental Caries', '일반', '충치의 의학적 명칭', '세균(뮤탄스균 등)이 당분을 분해하여 산을 생성하고, 이 산에 의해 치아 경조직이 탈회(무기질 용해)되는 감염성 질환입니다. 충치의 정식 의학 용어입니다.', 'cavity', '충치,법랑질,세균', 2, 0),
('fluoride', '불소', 'Fluoride', '일반', '충치 예방에 효과적인 광물질', '치아의 법랑질을 강화하고, 충치를 유발하는 세균의 활동을 억제하는 광물질입니다. 불소 도포, 불소 양치액, 불소 치약 등으로 적용하며, 특히 어린이 충치 예방에 효과적입니다.', NULL, '충치 예방,법랑질,실란트', 1, 0),
('sealant', '실란트', 'Sealant', '일반', '치아 홈을 메워 충치를 예방하는 치료', '어금니의 깊은 홈(소와열구)에 플라스틱 재료를 채워 음식물과 세균이 끼는 것을 방지하는 예방 치료입니다. 주로 어린이의 영구 어금니에 시행하며, 보험 적용됩니다.', NULL, '충치 예방,불소,어린이', 1, 0),
('sensitivity', '시린이', 'Tooth Sensitivity', '일반', '치아가 시린 증상', '차가운 음식, 뜨거운 음식, 단 음식 등에 치아가 시리거나 통증을 느끼는 증상입니다. 잇몸 퇴축, 법랑질 마모, 충치, 이갈이 등이 원인이며, 원인에 따라 치료법이 다릅니다.', NULL, '법랑질,상아질,잇몸 퇴축', 1, 0),
('amalgam', '아말감', 'Amalgam', '일반', '은-수은 합금 충전 재료', '과거에 널리 사용된 충치 충전 재료로, 은, 주석, 구리, 수은의 합금입니다. 내구성이 좋지만 심미성이 떨어지고 수은 우려로 현재는 레진이나 세라믹이 선호됩니다.', 'cavity', '레진,충치,충전', 2, 0),

-- ===== 5. 외과 (30개) =====
('extraction', '발치', 'Tooth Extraction', '외과', '치아를 뽑는 시술', '치료가 불가능할 정도로 손상되었거나, 매복된 사랑니, 교정 목적 등으로 치아를 제거하는 시술입니다. 국소마취 후 진행되며, 단순 발치와 수술적 발치(절개, 골삭제 필요)가 있습니다.', 'wisdom-tooth', '사랑니,매복치,국소마취', 1, 1),
('wisdom-tooth', '사랑니', 'Wisdom Tooth', '외과', '세 번째 큰어금니(제3대구치)', '가장 늦게 나는 어금니로, 보통 17~25세에 맹출합니다. 공간이 부족하면 매복(뼈 속에 묻힘)되거나 비스듬히 나서 염증, 인접 치아 충치 등 문제를 일으킵니다.', 'wisdom-tooth', '발치,매복치,지치주위염', 1, 1),
('impacted-tooth', '매복치', 'Impacted Tooth', '외과', '뼈나 잇몸 속에 묻혀 있는 치아', '정상적으로 맹출하지 못하고 턱뼈나 잇몸 안에 완전히 또는 부분적으로 묻혀 있는 치아입니다. 사랑니에서 가장 흔하며, X-ray나 CT로 확인합니다.', 'wisdom-tooth', '사랑니,발치,3D CT', 2, 0),
('pericoronitis', '지치주위염', 'Pericoronitis', '외과', '사랑니 주위 잇몸 염증', '불완전하게 맹출한 사랑니 주변 잇몸에 세균이 감염되어 발생하는 염증입니다. 붓고 아프며, 입을 벌리기 어려울 수 있습니다. 반복되면 사랑니 발치를 권장합니다.', 'wisdom-tooth', '사랑니,매복치,발치', 2, 0),
('oral-surgery', '구강외과', 'Oral and Maxillofacial Surgery', '외과', '구강, 턱, 얼굴 부위 수술 전문 분야', '치아 발치, 임플란트, 턱뼈 수술, 낭종 제거, 외상 치료 등 구강과 악안면(턱-얼굴) 영역의 수술을 전문으로 하는 치의학 분과입니다.', NULL, '발치,임플란트,턱뼈', 2, 0),
('local-anesthesia', '국소마취', 'Local Anesthesia', '외과', '치료 부위만 마취하는 방법', '시술 부위 주변에 마취제를 주사하여 해당 부분의 감각만 차단하는 마취 방법입니다. 의식은 정상이며, 치과 시술의 대부분에 사용됩니다. 1~3시간 후 마취가 풀립니다.', NULL, '발치,임플란트,시술', 1, 0),
('suture', '봉합', 'Suture', '외과', '절개한 부위를 실로 꿰매는 것', '수술이나 발치 후 잇몸 등 연조직을 실로 꿰매어 상처를 닫는 과정입니다. 흡수성 실(저절로 녹음)과 비흡수성 실(제거 필요)이 있습니다. 보통 7~10일 후 실밥 제거합니다.', 'wisdom-tooth', '발치,수술,실밥', 1, 0),
('dry-socket', '건성 소켓', 'Dry Socket', '외과', '발치 후 혈병이 빠져 뼈가 노출된 상태', '발치 후 상처 부위에 형성되어야 할 혈병(피떡)이 빠지거나 녹아 뼈가 노출되는 합병증입니다. 심한 통증이 특징이며, 보통 발치 후 2~5일 사이에 발생합니다.', 'wisdom-tooth', '발치,사랑니,합병증', 2, 0),
('cbct', '3D CT (CBCT)', 'Cone Beam Computed Tomography', '외과', '치과용 3차원 컴퓨터 단층촬영', '원추형 X선 빔으로 턱뼈와 치아의 3차원 영상을 촬영하는 장비입니다. 임플란트 식립 계획, 매복치 위치 확인, 턱뼈 상태 분석 등에 필수적입니다.', NULL, '임플란트,매복치,디지털', 2, 1),
('panorama', '파노라마', 'Panoramic X-ray', '외과', '전체 턱과 치아를 한 장에 촬영하는 X-ray', '위아래 턱뼈, 전체 치아, 턱관절, 상악동 등을 한 장의 X-ray에 담는 촬영법입니다. 전반적인 구강 상태를 파악하는 기본 검사이며, 임플란트, 교정, 발치 전 필수 촬영입니다.', NULL, '3D CT,X-ray,진단', 1, 0),
('cyst', '낭종', 'Cyst', '외과', '턱뼈나 잇몸에 생기는 주머니 형태 병소', '턱뼈나 연조직에 액체가 찬 주머니 형태로 생기는 양성 병소입니다. 치근단 낭종, 함치성 낭종 등이 있으며, 커지면 주변 뼈를 녹이므로 수술적 제거가 필요합니다.', NULL, '턱뼈,수술,3D CT', 3, 0),
('inferior-alveolar-nerve', '하치조신경', 'Inferior Alveolar Nerve', '외과', '아래턱의 주요 감각 신경', '아래턱뼈 속을 지나는 감각 신경으로, 아랫니와 아랫입술, 턱의 감각을 담당합니다. 사랑니 발치나 하악 임플란트 시 이 신경의 위치를 정확히 파악하는 것이 매우 중요합니다.', 'wisdom-tooth', '사랑니,발치,3D CT,신경', 3, 0),

-- ===== 6. 치주 (25개) =====
('periodontitis', '치주염', 'Periodontitis', '치주', '잇몸과 치조골이 파괴되는 염증 질환', '치은염이 진행되어 잇몸뿐 아니라 치아를 지지하는 뼈(치조골)까지 파괴되는 질환입니다. 성인 치아 상실의 가장 큰 원인이며, 초기에는 증상이 없어 정기 검진이 중요합니다.', NULL, '치은염,치석,스케일링,치조골', 1, 1),
('gingivitis', '치은염', 'Gingivitis', '치주', '잇몸에 생기는 염증', '치태(플라크)와 치석에 의해 잇몸에 염증이 생긴 상태입니다. 잇몸이 빨갛게 붓고, 양치 시 피가 나며, 냄새가 날 수 있습니다. 스케일링과 올바른 양치로 회복 가능합니다.', NULL, '치주염,치석,스케일링', 1, 0),
('scaling', '스케일링', 'Scaling', '치주', '치석을 제거하는 기본 잇몸 치료', '초음파 기구를 이용하여 치아와 잇몸 사이에 쌓인 치석(석회화된 세균막)을 제거하는 시술입니다. 만 19세 이상 연 1회 건강보험 적용됩니다. 잇몸 질환 예방의 기본입니다.', 'scaling', '치석,치태,잇몸,보험', 1, 1),
('calculus', '치석', 'Dental Calculus', '치주', '석회화된 치태(세균막)', '치태(플라크)가 타액의 칼슘 등과 결합하여 돌처럼 굳어진 것입니다. 양치만으로는 제거가 불가능하며, 스케일링으로 제거해야 합니다. 치석은 세균의 온상이 됩니다.', 'scaling', '스케일링,치태,잇몸', 1, 0),
('plaque', '치태', 'Dental Plaque', '치주', '치아 표면의 세균막', '치아 표면에 끊임없이 형성되는 끈적끈적한 세균막입니다. 음식물의 당분을 분해하여 산을 만들어 충치를 유발하고, 독소를 분비하여 잇몸 질환을 일으킵니다.', NULL, '치석,충치,양치,잇몸', 1, 0),
('periodontal-pocket', '치주낭', 'Periodontal Pocket', '치주', '치아와 잇몸 사이의 비정상적으로 깊어진 틈', '정상적으로 1~3mm인 치아와 잇몸 사이 틈(치은열구)이 치주염으로 인해 4mm 이상 깊어진 것입니다. 깊어질수록 세균이 자라기 좋은 환경이 되어 치주염이 악화됩니다.', NULL, '치주염,잇몸,치조골', 2, 0),
('gingival-recession', '잇몸 퇴축', 'Gingival Recession', '치주', '잇몸이 내려가 치아 뿌리가 노출되는 현상', '잇몸이 아래로 내려가 치아의 뿌리(치근)가 노출되는 상태입니다. 과도한 양치질, 치주염, 교합 이상 등이 원인이며, 시린이 증상이 나타나고 심미적으로도 좋지 않습니다.', NULL, '시린이,치주염,양치', 1, 0),
('curettage', '큐렛', 'Curettage', '치주', '치주낭 내부를 긁어내는 치주 치료', '치주낭 내벽의 감염된 조직과 치석을 기구(큐렛)로 긁어 제거하는 치주 치료법입니다. 스케일링만으로 개선되지 않는 중등도 치주염에 시행합니다.', NULL, '치주염,치주낭,스케일링', 3, 0),
('splint', '스플린트', 'Splint', '치주', '흔들리는 치아를 고정하는 장치', '치주염으로 흔들리는 치아들을 인접 치아와 연결하여 고정하는 치료법 또는 장치입니다. 이갈이 치료용 교합 스플린트도 있으며, 턱관절 장애 치료에도 사용됩니다.', NULL, '치주염,이갈이,턱관절', 2, 0),
('halitosis', '구취', 'Halitosis', '치주', '입에서 나는 불쾌한 냄새', '입에서 나는 불쾌한 냄새로, 원인의 약 90%가 구강 내에 있습니다. 치주염, 설태(혀 위 세균막), 충치, 불량 보철 등이 주요 원인입니다. 근본 원인 치료가 중요합니다.', NULL, '치주염,치석,양치', 1, 0),

-- ===== 7. 영상/장비 (20개) =====
('digital-dentistry', '디지털 치과', 'Digital Dentistry', '장비', '디지털 기술을 활용한 현대 치과 진료', '3D CT, 구강 스캐너, CAD/CAM, 디지털 교합기 등 디지털 기술을 활용하여 진단과 치료의 정확도를 높이는 현대 치과 진료 방식입니다. 강남치과의원은 디지털 치과를 지향합니다.', NULL, 'CEREC,3D CT,PrimeScan,디지털', 1, 1),
('oral-scanner', '구강 스캐너', 'Intraoral Scanner', '장비', '입 안을 3D로 스캔하는 장비', '구강 내부를 광학 카메라로 촬영하여 3D 디지털 모형을 만드는 장비입니다. 기존 본뜨기(인상채득)의 불편함을 해소하며, PrimeScan, iTero 등이 대표적입니다.', NULL, 'PrimeScan,iTero,디지털,CEREC', 1, 0),
('xray', 'X-ray', 'Dental X-ray', '장비', '치과용 방사선 촬영', '방사선을 이용하여 치아와 턱뼈의 내부 구조를 촬영하는 검사입니다. 치근단, 교익, 파노라마, CBCT 등 다양한 촬영 방법이 있으며, 충치, 치주질환, 매복치 등을 진단합니다.', NULL, '파노라마,3D CT,진단', 1, 0),
('periapical', '치근단 촬영', 'Periapical X-ray', '장비', '치아 뿌리 끝까지 촬영하는 소형 X-ray', '개별 치아의 전체 모습(치관~치근 끝)을 촬영하는 소형 X-ray입니다. 충치 깊이, 치근 상태, 치근단 병소 등을 정밀하게 확인합니다.', NULL, 'X-ray,파노라마,진단', 2, 0),
('autoclave', '오토클레이브', 'Autoclave', '장비', '고압 증기 멸균기', '121~134℃의 고온 고압 증기로 치과 기구를 완전히 멸균하는 장비입니다. 세균, 바이러스, 아포까지 제거하여 교차 감염을 방지합니다. 감염관리의 핵심 장비입니다.', NULL, '감염관리,멸균,위생', 2, 0),
('led-curing', 'LED 광조사기', 'LED Curing Light', '장비', '레진을 굳히는 빛을 쏘는 장비', '광중합(빛으로 굳히는) 레진을 경화시키는 데 사용하는 장비입니다. 특정 파장의 LED 빛을 레진에 조사하면 화학 반응이 일어나 레진이 단단하게 굳어집니다.', NULL, '레진,충치 치료,충전', 2, 0),

-- ===== 8. 소아/예방 (15개) =====
('pediatric', '소아치과', 'Pediatric Dentistry', '소아', '어린이 전문 치과 분야', '영유아부터 청소년까지의 구강 건강을 전문으로 다루는 분야입니다. 유치 관리, 충치 예방, 교합 유도, 불소 도포, 실란트 등을 시행합니다.', NULL, '유치,영구치,실란트,불소', 1, 0),
('deciduous-tooth', '유치', 'Deciduous Tooth / Baby Tooth', '소아', '첫 번째로 나는 치아(젖니)', '생후 6개월부터 나기 시작하여 총 20개가 나는 첫 번째 치아입니다. 6~12세에 걸쳐 영구치로 교체됩니다. 유치 관리가 영구치 건강의 기초가 됩니다.', NULL, '영구치,소아치과,충치', 1, 0),
('permanent-tooth', '영구치', 'Permanent Tooth', '소아', '유치가 빠진 후 나는 영구적인 치아', '유치가 빠진 후 나오는 성인의 치아로, 총 28~32개(사랑니 포함)입니다. 6세경 첫 번째 큰어금니(제1대구치)부터 나기 시작합니다. 한번 손상되면 재생되지 않습니다.', NULL, '유치,사랑니,소아치과', 1, 0),
('fluoride-application', '불소 도포', 'Fluoride Application', '소아', '치아에 불소를 직접 바르는 예방 치료', '고농도 불소를 치아 표면에 직접 도포하여 법랑질을 강화하고 충치를 예방하는 시술입니다. 주로 어린이에게 시행하며, 3~6개월 간격으로 정기적으로 받는 것을 권장합니다.', NULL, '불소,충치 예방,실란트', 1, 0),
('supernumerary', '과잉치', 'Supernumerary Tooth', '소아', '정상 개수보다 많은 여분의 치아', '정상 치아 수보다 추가로 발생한 치아입니다. 영구치 맹출을 방해하거나 치열을 흐트러뜨릴 수 있어, 발견 시 발치가 필요한 경우가 많습니다.', NULL, '영구치,발치,교정', 2, 0),
('space-maintainer', '공간 유지 장치', 'Space Maintainer', '소아', '유치 조기 상실 시 공간을 유지하는 장치', '유치가 정상 교체 시기보다 일찍 빠졌을 때, 영구치가 나올 공간을 확보하기 위해 장착하는 장치입니다. 인접 치아가 빈 공간으로 이동하는 것을 방지합니다.', NULL, '유치,영구치,소아치과', 2, 0),
('bruxism', '이갈이', 'Bruxism', '소아', '수면 중 또는 낮에 이를 가는 습관', '무의식적으로 이를 갈거나 악무는 습관입니다. 치아 마모, 턱관절 통증, 두통 등을 유발합니다. 스트레스, 교합 이상 등이 원인이며, 교합 스플린트로 치료합니다.', NULL, '턱관절,스플린트,마모', 1, 0),

-- ===== 9. 보험/행정 (15개) =====
('health-insurance', '건강보험', 'National Health Insurance', '보험', '국민건강보험 적용 치과 치료', '국민건강보험공단에서 보장하는 치과 치료 항목입니다. 스케일링(연 1회), 레진 충전(12세 이하), 치석 제거, 발치, X-ray 등이 보험 적용되며, 본인부담금만 납부합니다.', NULL, '스케일링,레진,보험 적용', 1, 1),
('non-covered', '비급여', 'Non-covered Treatment', '보험', '건강보험이 적용되지 않는 치료', '건강보험으로 보장되지 않아 환자가 전액 부담하는 치료입니다. 임플란트(65세 이상 제외), 교정, 미백, 라미네이트, 심미 보철 등이 해당됩니다.', NULL, '건강보험,임플란트,교정', 1, 0),
('copayment', '본인부담금', 'Copayment', '보험', '건강보험 적용 시 환자가 내는 금액', '건강보험 적용 치료 시 총 진료비에서 환자가 부담하는 비율의 금액입니다. 치과의원 기준 일반적으로 30%입니다. 나머지 70%는 건강보험공단이 부담합니다.', NULL, '건강보험,보험 적용', 1, 0),
('senior-implant', '노인 임플란트', 'Senior Implant Coverage', '보험', '만 65세 이상 임플란트 보험 적용', '만 65세 이상 국민은 평생 2개까지 임플란트에 건강보험이 적용됩니다. 본인부담금 30%(일반) 또는 10~20%(차상위, 의료급여)로 임플란트 시술을 받을 수 있습니다.', 'implant', '임플란트,건강보험,본인부담금', 1, 0),
('dental-chart', '치식', 'Dental Chart / Numbering', '보험', '치아 번호 체계', '각 치아에 고유 번호를 부여하는 체계입니다. FDI 방식(국제)은 2자리 숫자로, 첫 자리는 사분악(1~4), 두 번째는 치아 순서(1~8)를 나타냅니다. 예: 36번 = 좌측 하악 제1대구치.', NULL, '진단,치아,기록', 2, 0),

-- ===== 10. 구강해부학 (20개) =====
('oral-anatomy', '구강 해부학', 'Oral Anatomy', '해부학', '입 안의 구조와 명칭', '치아, 잇몸, 혀, 구개(입천장), 점막, 턱뼈, 타액선 등 구강 내 구조물의 형태와 기능을 다루는 분야입니다. 정확한 진단과 치료를 위한 기초 지식입니다.', NULL, '치아,잇몸,턱뼈,혀', 2, 0),
('gingiva', '잇몸', 'Gingiva', '해부학', '치아를 둘러싼 분홍색 연조직', '치아 주위를 둘러싸고 있는 점막 조직으로, 치아와 턱뼈를 보호합니다. 건강한 잇몸은 연분홍색이며, 단단하고 피가 나지 않습니다. 빨갛게 붓거나 피가 나면 잇몸 질환 신호입니다.', NULL, '치은염,치주염,잇몸 퇴축', 1, 0),
('tongue', '혀', 'Tongue', '해부학', '맛을 느끼고 음식을 삼키는 근육 기관', '구강 바닥에 위치한 근육 기관으로, 맛을 느끼고, 음식물을 씹고 삼키는 것을 돕고, 발음에 중요한 역할을 합니다. 설태(혀 위 세균막)가 구취의 원인이 되기도 합니다.', NULL, '구취,구강,해부학', 1, 0),
('palate', '구개', 'Palate', '해부학', '입천장', '구강의 윗부분을 이루는 구조물입니다. 앞부분의 딱딱한 경구개(뼈가 있음)와 뒷부분의 부드러운 연구개(근육)로 나뉩니다. 음식을 삼키고 발음하는 데 중요합니다.', NULL, '구강,해부학', 2, 0),
('salivary-gland', '타액선', 'Salivary Gland', '해부학', '침(타액)을 분비하는 분비샘', '타액(침)을 생산하고 분비하는 기관입니다. 이하선, 악하선, 설하선 등 큰 타액선과 입 안 점막에 분포한 작은 타액선이 있습니다. 하루 약 1~1.5리터의 타액을 생산합니다.', NULL, '구강건조증,타액,해부학', 2, 0),
('tooth-root', '치근', 'Tooth Root', '해부학', '치아의 뿌리 부분', '잇몸과 뼈 속에 묻혀 있는 치아의 아래 부분입니다. 치조골에 단단히 고정되어 씹는 힘을 지지하며, 내부에 신경과 혈관이 지나는 근관이 있습니다.', NULL, '치조골,근관,신경치료', 1, 0),
('tooth-crown-anatomy', '치관', 'Tooth Crown (Anatomical)', '해부학', '치아의 잇몸 위로 보이는 부분', '잇몸 위로 노출되어 눈에 보이는 치아의 윗부분입니다. 법랑질로 덮여 있으며, 음식을 씹는 기능과 심미적 역할을 합니다. 보철에서의 크라운과는 다른 해부학적 용어입니다.', NULL, '법랑질,치근,해부학', 1, 0),
('cementum', '백악질', 'Cementum', '해부학', '치아 뿌리를 감싸는 얇은 층', '치근(뿌리) 표면을 덮고 있는 얇은 경조직으로, 치주인대가 부착되는 곳입니다. 법랑질과 경계를 이루며, 잇몸 퇴축 시 노출되면 시린이의 원인이 됩니다.', NULL, '치근,법랑질,치주인대', 3, 0),
('periodontal-ligament', '치주인대', 'Periodontal Ligament', '해부학', '치아와 뼈를 연결하는 인대', '치아 뿌리와 치조골 사이에 있는 섬유 조직입니다. 치아를 뼈에 고정하고, 씹는 힘의 충격을 흡수하며, 치아의 미세한 움직임을 가능하게 합니다.', NULL, '치조골,치근,치주염', 3, 0),
('maxilla', '상악', 'Maxilla', '해부학', '위턱뼈', '얼굴의 중앙 부위를 형성하는 위쪽 턱뼈입니다. 윗니가 식립되어 있으며, 상악동(부비강)을 포함합니다. 위턱 임플란트 시 상악동과의 관계가 중요합니다.', NULL, '하악,상악동,임플란트', 2, 0),
('mandible', '하악', 'Mandible', '해부학', '아래턱뼈', '얼굴에서 유일하게 움직이는 뼈인 아래쪽 턱뼈입니다. 아랫니가 식립되어 있으며, 하치조신경이 지나갑니다. 단단하고 밀도가 높아 임플란트 골유착이 잘 됩니다.', NULL, '상악,하치조신경,턱관절', 2, 0),
('occlusion', '교합', 'Occlusion', '해부학', '위아래 치아가 맞물리는 것', '위아래 치아가 서로 접촉하여 맞물리는 것, 또는 그 관계를 말합니다. 정상 교합은 음식을 효율적으로 씹고, 턱관절에 무리가 가지 않도록 합니다.', NULL, '부정교합,교정,턱관절', 1, 0),
('apex', '치근단', 'Apex', '해부학', '치아 뿌리의 끝부분', '치아 뿌리의 맨 끝 부분으로, 혈관과 신경이 치아 내부로 들어오는 입구(근단공)가 있습니다. 치근단 염증이 생기면 근관치료(신경치료)가 필요합니다.', 'root-canal', '치근,신경치료,근관', 2, 0),
('xerostomia', '구강건조증', 'Xerostomia', '해부학', '입이 마르는 증상', '타액(침) 분비가 줄어 입이 마르는 증상입니다. 약물 부작용, 방사선 치료, 쇼그렌 증후군, 노화 등이 원인입니다. 충치와 잇몸 질환 위험이 증가하며, 인공 타액 등으로 관리합니다.', NULL, '타액선,충치,잇몸', 1, 0);
